    public static String stateIdToString(StateId id)
    {
        switch (id)
        {
            case ROOT: return "ROOT";
            case FOLLOWING: return "FOLLOWING";
            case SEARCHING: return "SEARCHING";
            case STARTING: return "STARTING";
            case TRACKING_FORWARD: return "TRACKING_FORWARD";
            case TRACKING_LEFT: return "TRACKING_LEFT";
            case TRACKING_RIGHT: return "TRACKING_RIGHT";
            case TRACKING_ROTATELEFT: return "TRACKING_ROTATELEFT";
            case TRACKING_ROTATERIGHT: return "TRACKING_ROTATERIGHT";
            case IDLE: return "IDLE";
            default: return "?";
        }
    }
    
