    protected String[] getAllowedEvents(StateId id) {
        return switch (id) {
            case ROOT -> new String[0];  // No events
            case FOLLOWING -> new String[]{"DO", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE", "CROSSPRESSED", "LOSTCONTROLLER", "STOPFOLLOW", "R2STICK"};
            case SEARCHING -> new String[]{"MIDDLEWHITE", "MIDDLEBLACK", "DO", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case STARTING -> new String[]{"DO", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case TRACKING_FORWARD -> new String[]{"MIDDLEWHITE", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "DO", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case TRACKING_LEFT -> new String[]{"MIDDLEWHITE", "DO", "MIDDLEBLACK", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case TRACKING_RIGHT -> new String[]{"MIDDLEWHITE", "DO", "MIDDLEBLACK", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case TRACKING_ROTATELEFT -> new String[]{"MIDDLEWHITE", "MIDDLEBLACK", "DO", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case TRACKING_ROTATERIGHT -> new String[]{"MIDDLEWHITE", "MIDDLEBLACK", "DO", "R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "LEFTBLACK", "LEFTWHITE", "RIGHTBLACK", "RIGHTWHITE"};
            case IDLE -> new String[]{"R2STICK", "STOPFOLLOW", "LOSTCONTROLLER", "CROSSPRESSED", "STARTFOLLOW"};
            default -> new String[0];
        };
    }
    
    @Override
    protected String[] getAllEventNames()
    {
        EventId[] values = EventId.values();
        String[] names = new String[values.length];
        
        for (int i = 0; i < values.length; i++)
            names[i] = translateEventName(values[i].name());
        
        return names;
    }
    
    @Override
    protected String[] getAllStateNames()
    {
        StateId[] values = StateId.values();
        String[] names = new String[values.length];
        
        for (int i = 0; i < values.length; i++)
            names[i] = values[i].name();
        
        return names;
    }
    
